@media (max-width: 768px) {
  .content-wrapper {
    flex-direction: column;
  }
  .sidebar, .aside {
    width: auto;
  }
}
```

## 现代 Grid 简写

```css
.modern-layout {
  display: grid;
  grid-template:
    "header header" auto
    "sidebar main" 1fr
    "footer footer" auto
    / 250px 1fr;
  min-height: 100vh;
  gap: 1rem;
}
```

使用 `grid-template` 可以同时定义行和列。

# 变量与数据类型

## JavaScript 是什么

JavaScript 是 Web 的编程语言，与 HTML（结构）和 CSS（样式）协同工作，实现网页的动态交互功能。

## 变量声明

JavaScript 有三种声明变量的方式：

```javascript
// let - 可重新赋值的变量（块级作用域，推荐）
let name = "Alice";
name = "Bob";  // ✓ 可以重新赋值

// const - 常量，声明时必须初始化（块级作用域，推荐）
const PI = 3.14159;
// PI = 3.14;  // ✗ 错误！不能重新赋值

// var - 函数作用域（旧用法，不推荐）
var age = 25;
```

**最佳实践**：默认使用 `const`，需要重新赋值时使用 `let`，避免使用 `var`。

## 数据类型

### 基本类型（Primitive）

```javascript
// String - 字符串
let username = "CodeQuest";

// Number - 数字（包括整数和浮点数）
let score = 95;
let price = 19.99;

// Boolean - 布尔值
let isActive = true;   // 或 false

// Undefined - 未定义
let data;              // 声明但未赋值，值为 undefined

// Null - 空值
let user = null;       // 表示"无"或"空"

// Symbol - 唯一标识（ES6）
let id = Symbol("id");
```

### 引用类型

```javascript
// Object - 对象
let person = { name: "Tom", age: 25 };

// Array - 数组
let fruits = ["apple", "banana", "cherry"];

// Function - 函数
function greet() { return "Hello"; }
```

## typeof 操作符

用于检测数据类型：

```javascript
typeof "hello";      // "string"
typeof 42;           // "number"
typeof true;         // "boolean"
typeof undefined;    // "undefined"
typeof null;         // "object" （历史 bug，需注意）
typeof {};           // "object"
typeof [];           // "object" （数组也是对象）
typeof function(){}; // "function"
```

## 类型转换

```javascript
// 显式转换
Number("42");        // 42
String(123);         // "123"
Boolean(1);          // true

// 模板字符串（推荐）
let name = "Alice";
let age = 25;
console.log(`我叫 ${name}，今年 ${age} 岁`);
// 输出：我叫 Alice，今年 25 岁
```

## 命名规范

- 使用驼峰命名法：`userName`, `totalScore`
- 常量全大写下划线：`MAX_SIZE`
- 变量名要有意义，避免单字母（循环中除外）
- 不能以数字开头，不能是保留字

# 条件语句

## if...else 语句

```javascript
let score = 85;

if (score >= 90) {
  console.log("优秀");
} else if (score >= 80) {
  console.log("良好");
} else if (score >= 70) {
  console.log("中等");
} else if (score >= 60) {
  console.log("及格");
} else {
  console.log("不及格");
}
```

## 三元运算符

简单的二选一，语法更简洁：

```javascript
let age = 18;
let status = age >= 18 ? "成年人" : "未成年人";

// 嵌套三元（不推荐过多嵌套）
let label = score >= 90 ? "A" : score >= 80 ? "B" : "C";
```

## switch 语句

用于多值匹配的场景：

```javascript
let day = 1;

switch (day) {
  case 1:
    console.log("星期一");
    break;  // 不要忘记 break，否则会穿透到下一个 case
  case 2:
    console.log("星期二");
    break;
  case 3:
    console.log("星期三");
    break;
  case 4:
    console.log("星期四");
    break;
  case 5:
    console.log("星期五");
    break;
  default:
    console.log("周末");
}

// 多个 case 共享代码
switch (fruit) {
  case "apple":
  case "pear":
  case "peach":
    console.log("蔷薇科水果");
    break;
  case "orange":
  case "lemon":
    console.log("柑橘类水果");
    break;
}
```

## 条件中的常见模式

```javascript
// 检查变量是否有值
if (name) { ... }  // 等价于 if (name !== "" && name !== null && name !== undefined)

// 使用逻辑或设置默认值
let username = input || "匿名用户";

// 可选执行（条件为真时才执行）
isLoggedIn && showUserProfile();

// 检查数组非空
if (items.length > 0) { ... }
// 或
if (items.length) { ... }
```

## 注意事项

```javascript
// 常见陷阱：== 的类型转换
if (0 == false) { ... }   // true！使用 === 避免

// 正确做法
if (isValid === true) { ... }  // 明确比较
if (isValid) { ... }           // 隐式转换，简洁但需理解真值假值

// 检查 null 或 undefined
if (value == null) { ... }  // 同时匹配 null 和 undefined（唯一适合用 == 的场景）
if (value === null || value === undefined) { ... }  // 等价的严格比较写法
```

