# 函数定义与调用

## 函数声明

使用 `function` 关键字声明，会**提升**（hoisting）：

```javascript
function greet(name) {
  return `Hello, ${name}!`;
}

console.log(greet("Alice"));  // "Hello, Alice!"
```

## 函数表达式

将函数赋值给变量，**不会提升**：

```javascript
const greet = function(name) {
  return `Hello, ${name}!`;
};
```

## 箭头函数（推荐）

更简洁的语法：

```javascript
// 完整写法
const greet = (name) => {
  return `Hello, ${name}!`;
};

// 简化写法：单参数可省略括号
const greet = name => {
  return `Hello, ${name}!`;
};

// 极简写法：单表达式可省略 {} 和 return
const greet = name => `Hello, ${name}!`;

// 多参数
const add = (a, b) => a + b;

// 无参数
const sayHi = () => console.log("Hi!");

// 返回对象需要用括号包裹
const getUser = name => ({ name: name, role: "user" });
```

## 默认参数

```javascript
function greet(name = "访客") {
  return `你好，${name}！`;
}

greet();         // "你好，访客！"
greet("Alice");  // "你好，Alice！"
```

## 剩余参数

```javascript
function sum(...numbers) {
  let total = 0;
  for (let num of numbers) {
    total += num;
  }
  return total;
}

sum(1, 2, 3, 4, 5);  // 15
```

## 作用域

### 全局作用域

在函数外部声明的变量，可在整个脚本中访问：

```javascript
let globalVar = "我是全局变量";

function test() {
  console.log(globalVar);  // 可以访问
}
```

### 局部（函数）作用域

在函数内部声明的变量，只能在函数内访问：

```javascript
function test() {
  let localVar = "我是局部变量";
  console.log(localVar);   // ✓ 可以
}
// console.log(localVar);  // ✗ 报错！
```

### 块级作用域

`let` 和 `const` 在 `{}` 块内有效：

```javascript
if (true) {
  let blockVar = "块级变量";
  const PI = 3.14;
}
// console.log(blockVar);  // ✗ 报错！
```

## 箭头函数的 this

箭头函数没有自己的 `this`，继承外层的 `this`：

```javascript
const person = {
  name: "Alice",
  regularFunc: function() {
    console.log(this.name);  // "Alice"（this 指向 person）
  },
  arrowFunc: () => {
    console.log(this.name);  // undefined（this 继承外层，不是 person）
  }
};
```

**规则**：需要 `this` 时用普通函数，不需要时用箭头函数。

# 数组操作

## 数组创建

```javascript
// 字面量创建（推荐）
let fruits = ["apple", "banana", "cherry"];

// 空数组
let empty = [];

// Array 构造函数
let numbers = new Array(1, 2, 3);

// 不同数据类型混合
let mixed = ["text", 42, true, null, { key: "value" }];
```

## 访问和修改元素

```javascript
let colors = ["red", "green", "blue"];

// 访问（索引从 0 开始）
colors[0];    // "red"
colors[2];    // "blue"
colors[10];   // undefined（越界）

// 修改
colors[1] = "yellow";  // ["red", "yellow", "blue"]

// 获取长度
colors.length;  // 3

// 访问最后一个元素
colors[colors.length - 1];  // "blue"
```

## 常用数组方法

### 添加/删除元素

```javascript
let arr = [1, 2, 3];

arr.push(4);        // [1,2,3,4] - 尾部添加
arr.pop();          // [1,2,3]   - 尾部删除
arr.unshift(0);     // [0,1,2,3] - 头部添加
arr.shift();        // [1,2,3]   - 头部删除
arr.splice(1, 1);   // [1,3]     - 从索引1删除1个元素
arr.splice(1, 0, "a"); // [1,"a",3] - 在索引1插入"a"
```

### 查找元素

```javascript
let nums = [10, 20, 30, 40, 50];

nums.indexOf(30);      // 2 - 返回索引，找不到返回 -1
nums.includes(30);     // true - 是否包含
nums.find(n => n > 25);     // 30 - 返回第一个满足条件的元素
nums.findIndex(n => n > 25); // 2 - 返回第一个满足条件的索引
```

### 遍历数组

```javascript
let items = ["a", "b", "c"];

// forEach - 遍历每个元素
items.forEach((item, index) => {
  console.log(`${index}: ${item}`);
});

// map - 映射每个元素，返回新数组
let upper = items.map(item => item.toUpperCase());
// ["A", "B", "C"]

// filter - 筛选满足条件的元素
let nums = [1, 2, 3, 4, 5, 6];
let evens = nums.filter(n => n % 2 === 0);
// [2, 4, 6]

// reduce - 累计计算
let sum = nums.reduce((total, n) => total + n, 0);
// 21
```

### 数组转换

```javascript
let words = ["Hello", "World"];

words.join(" ");       // "Hello World" - 合并为字符串
words.slice(0, 2);     // ["Hello", "World"] - 提取子数组
words.reverse();       // ["World", "Hello"] - 反转（修改原数组）
words.concat(["!"]);   // ["World", "Hello", "!"] - 合并数组
```

## 数组解构

```javascript
let [first, second] = ["apple", "banana"];
console.log(first);   // "apple"

// 跳过元素
let [, , third] = [1, 2, 3, 4];
console.log(third);   // 3

// 剩余元素
let [head, ...tail] = [1, 2, 3, 4];
console.log(head);    // 1
console.log(tail);    // [2, 3, 4]
```

# 对象与类

## 对象基础

对象用于存储键值对数据：

```javascript
// 字面量创建（推荐）
let person = {
  name: "Alice",
  age: 25,
  city: "Beijing"
};

// 构造函数创建
let user = new Object();
user.name = "Bob";
user.age = 30;
```

## 属性访问和修改

```javascript
let person = { name: "Alice", age: 25 };

// 点表示法
person.name;        // "Alice"
person.age = 26;    // 修改

// 方括号表示法（适用于变量或特殊字符键）
person["name"];     // "Alice"
let key = "age";
person[key];        // 26

// 添加属性
person.email = "alice@example.com";

// 删除属性
delete person.age;
```

## 对象方法

```javascript
let person = {
  name: "Alice",
  greet() {
    return `你好，我是 ${this.name}`;
  }
};

person.greet();  // "你好，我是 Alice"
```

## ES6 Class

```javascript
class Animal {
  // 构造函数
  constructor(name) {
    this.name = name;
  }

  // 方法
  speak() {
    console.log(`${this.name} 发出声音`);
  }

  // 静态方法
  static isAnimal(obj) {
    return obj instanceof Animal;
  }
}

// 继承
class Dog extends Animal {
  constructor(name, breed) {
    super(name);  // 调用父类构造函数
    this.breed = breed;
  }

  speak() {
    console.log(`${this.name} 汪汪叫`);
  }
}

let dog = new Dog("旺财", "金毛");
dog.speak();  // "旺财 汪汪叫"
```

## 对象常用方法

```javascript
let person = { name: "Alice", age: 25, city: "Beijing" };

Object.keys(person);    // ["name", "age", "city"]
